@page "/courses"
@inject CatalogService CatalogService

<PageTitle>Courses</PageTitle>

<h1>@(currentDepartment is not null ? currentDepartment.Name + " Courses" : "All Courses")</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-5">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(dept.Id == DepartmentId)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button type="submit" class="btn btn-primary">Search</button>
        <a href="courses" class="btn btn-outline-secondary ms-1">Clear</a>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>ID</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Id</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? DepartmentId { get; set; }

    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();
    private Department? currentDepartment;

    protected override void OnParametersSet()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(DepartmentId, Search);
        currentDepartment = !string.IsNullOrWhiteSpace(DepartmentId) ? CatalogService.GetDepartment(DepartmentId) : null;
    }
}

@page "/enroll"
@inject CatalogService CatalogService

<PageTitle>Enroll</PageTitle>

<h1>Course Enrollment</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
        <p>Student ID: @Model.StudentId</p>
    </div>
    <a href="courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    <p>Fill out the form below to request enrollment in a course.</p>

    <EditForm Model="Model" method="post" FormName="enrollment" Enhance OnValidSubmit="HandleSubmit">
        <AntiforgeryToken />
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Student Name</label>
            <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
            <ValidationMessage For="() => Model.StudentName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
            <ValidationMessage For="() => Model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                <option value="">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Id - @course.Title (@course.DepartmentName)</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public string? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = "";

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses(null, null);

        if (!string.IsNullOrWhiteSpace(CourseId) && string.IsNullOrWhiteSpace(Model.CourseId))
        {
            Model.CourseId = CourseId;
        }
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(Model.CourseId);
        selectedCourseTitle = course?.Title ?? Model.CourseId;
        CatalogService.SubmitEnrollmentRequest(Model);
        submitted = true;
    }
}

